/**
 * The Void — Item Catalog & Drop System Tests
 *
 * Verifies:
 * - Drop tables exist for all gnostic dimensions
 * - Rarity scales with dimension (higher dims = rarer drops)
 * - Math-based drop probabilities (1/β₁)
 * - Boss drops are guaranteed
 * - Failure unlocks rare table (failure finds the good stuff)
 * - Item modifiers are balanced (no broken items)
 * - Inventory and equipment slot validation
 * - Nexus value correlates with rarity
 */

import { describe, it, expect } from 'vitest';
import {
  ITEM_CATALOG,
  DIMENSION_DROP_TABLES,
  getItemsForDimension,
  resolveDrops,
  createEmptyInventory,
  calculateEquipmentModifier,
  calculateNexusValue,
  IDENTITY_MODIFIER,
  MAX_INVENTORY_SLOTS,
  type ResolvedDrop,
} from '../void-item-catalog';
import type { DimensionIndex } from '../void-game-types';

// Simple mulberry32 PRNG for test determinism
function mulberry32(seed: number): () => number {
  let s = seed | 0;
  return () => {
    s = (s + 0x6d2b79f5) | 0;
    let t = Math.imul(s ^ (s >>> 15), 1 | s);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

describe('void-item-catalog', () => {
  // ── Catalog Integrity ───────────────────────────────────────────

  describe('ITEM_CATALOG', () => {
    it('has items for multiple dimensions', () => {
      expect(ITEM_CATALOG.size).toBeGreaterThanOrEqual(20);
    });

    it('all items have valid categories', () => {
      const validCategories = [
        'weapon', 'armor', 'consumable', 'material',
        'relic', 'cosmetic', 'key', 'blueprint',
      ];
      for (const [, item] of ITEM_CATALOG) {
        expect(validCategories).toContain(item.category);
      }
    });

    it('all items have valid slots', () => {
      const validSlots = [
        'mainhand', 'offhand', 'helm', 'chest', 'legs',
        'boots', 'trinket_1', 'trinket_2', 'none',
      ];
      for (const [, item] of ITEM_CATALOG) {
        expect(validSlots).toContain(item.slot);
      }
    });

    it('consumables and materials use slot "none"', () => {
      for (const [, item] of ITEM_CATALOG) {
        if (item.category === 'consumable' || item.category === 'material') {
          expect(item.slot).toBe('none');
        }
      }
    });

    it('weapons and armor have maxStack 1', () => {
      for (const [, item] of ITEM_CATALOG) {
        if (item.category === 'weapon' || item.category === 'armor' || item.category === 'relic') {
          expect(item.maxStack).toBe(1);
        }
      }
    });
  });

  // ── Rarity Scaling ──────────────────────────────────────────────

  describe('rarity scaling', () => {
    it('higher dimensions have rarer items', () => {
      const rarityOrder = ['common', 'uncommon', 'rare', 'epic', 'legendary', 'mythic', 'cosmic'];
      const dimMaxRarity = new Map<number, number>();

      for (const [, item] of ITEM_CATALOG) {
        const rarityIndex = rarityOrder.indexOf(item.rarity);
        const current = dimMaxRarity.get(item.nativeDimension) ?? -1;
        dimMaxRarity.set(item.nativeDimension, Math.max(current, rarityIndex));
      }

      // Dimension 9 items should be cosmic (index 6)
      expect(dimMaxRarity.get(9)).toBe(6);
      // Dimension 0 items should be common (index 0)
      expect(dimMaxRarity.get(0)).toBe(0);
    });

    it('Pleroma items are cosmic tier', () => {
      const plerItems = getItemsForDimension(9);
      for (const item of plerItems) {
        if (item.category !== 'material') {
          expect(item.rarity).toBe('cosmic');
        }
      }
    });
  });

  // ── Drop Resolution ─────────────────────────────────────────────

  describe('resolveDrops', () => {
    it('returns drops from common table on normal encounters', () => {
      const rng = mulberry32(42);
      // Dimension 3 (Proton), β₁=3, normal encounter
      const drops = resolveDrops(3, 3, false, false, rng, 0);
      // May or may not get drops — but the function doesn't crash
      expect(Array.isArray(drops)).toBe(true);
    });

    it('failure unlocks the rare table', () => {
      // Run many encounters with failure=true and count rare drops
      let rareDrops = 0;
      for (let i = 0; i < 500; i++) {
        const rng = mulberry32(i * 17);
        const drops = resolveDrops(3, 3, true, false, rng, 10);
        for (const drop of drops) {
          if (drop.item.rarity === 'rare' || drop.item.rarity === 'epic') {
            rareDrops++;
          }
        }
      }
      // Should get SOME rare drops from failures
      expect(rareDrops).toBeGreaterThan(0);
    });

    it('boss encounters always drop from boss table', () => {
      let bossDropCount = 0;
      for (let i = 0; i < 100; i++) {
        const rng = mulberry32(i);
        const drops = resolveDrops(3, 3, false, true, rng, 50);
        for (const drop of drops) {
          if (drop.item.itemId.startsWith('boss-')) {
            bossDropCount++;
          }
        }
      }
      // Boss drops should be guaranteed (every encounter)
      expect(bossDropCount).toBe(100);
    });

    it('higher dimensions produce fewer but rarer drops', () => {
      // Compare drop rates between dim 3 (β₁=3) and dim 8 (β₁=21)
      let dim3Drops = 0;
      let dim8Drops = 0;

      for (let i = 0; i < 1000; i++) {
        const rng3 = mulberry32(i);
        const rng8 = mulberry32(i + 100000);
        dim3Drops += resolveDrops(3, 3, true, false, rng3, 50).length;
        dim8Drops += resolveDrops(8, 21, true, false, rng8, 250).length;
      }

      // Dim 8 should produce fewer total drops (higher β₁ = lower probability per roll)
      expect(dim3Drops).toBeGreaterThan(dim8Drops);
    });

    it('each drop carries improbability for Nexus pricing', () => {
      const rng = mulberry32(999);
      const drops = resolveDrops(3, 3, true, true, rng, 100);
      for (const drop of drops) {
        expect(drop.improbability).toBeGreaterThan(0);
      }
    });
  });

  // ── Item Modifiers ──────────────────────────────────────────────

  describe('item modifiers', () => {
    it('no item has negative R bonus', () => {
      for (const [, item] of ITEM_CATALOG) {
        expect(item.modifier.rBonus).toBeGreaterThanOrEqual(0);
      }
    });

    it('v multiplier is always in (0, 1] range', () => {
      for (const [, item] of ITEM_CATALOG) {
        expect(item.modifier.vMultiplier).toBeGreaterThan(0);
        expect(item.modifier.vMultiplier).toBeLessThanOrEqual(1);
      }
    });

    it('higher dimension items have stronger modifiers', () => {
      // Compare average modifier power across dimensions
      const dimPower = new Map<number, number[]>();

      for (const [, item] of ITEM_CATALOG) {
        if (item.category === 'material') continue; // Materials have no modifiers
        const power = item.modifier.rBonus +
          (1 - item.modifier.vMultiplier) * 100 +
          item.modifier.wBonus * 10;

        const current = dimPower.get(item.nativeDimension) ?? [];
        current.push(power);
        dimPower.set(item.nativeDimension, current);
      }

      // Average power of dim 9 items should exceed dim 3 items
      const avg3 = (dimPower.get(3) ?? [0]).reduce((a, b) => a + b, 0) / (dimPower.get(3)?.length ?? 1);
      const avg9 = (dimPower.get(9) ?? [0]).reduce((a, b) => a + b, 0) / (dimPower.get(9)?.length ?? 1);
      expect(avg9).toBeGreaterThan(avg3);
    });
  });

  // ── Inventory & Equipment ───────────────────────────────────────

  describe('inventory', () => {
    it('creates empty inventory with null equipment', () => {
      const inv = createEmptyInventory();
      expect(inv.slots).toHaveLength(0);
      expect(inv.equipment.mainhand).toBeNull();
      expect(inv.equipment.helm).toBeNull();
    });
  });

  describe('calculateEquipmentModifier', () => {
    it('returns identity for empty equipment', () => {
      const inv = createEmptyInventory();
      const mod = calculateEquipmentModifier(inv.equipment);
      expect(mod.rBonus).toBe(0);
      expect(mod.vMultiplier).toBe(1);
      expect(mod.wBonus).toBe(0);
    });

    it('stacks modifiers from multiple equipped items', () => {
      const inv = createEmptyInventory();
      const blade = ITEM_CATALOG.get('barbelo-sliver-blade');
      const ring = ITEM_CATALOG.get('proton-confinement-ring');
      expect(blade).toBeDefined();
      expect(ring).toBeDefined();

      const equipped = {
        ...inv.equipment,
        mainhand: blade!,
        trinket_1: ring!,
      };

      const mod = calculateEquipmentModifier(equipped);
      expect(mod.rBonus).toBe(blade!.modifier.rBonus + ring!.modifier.rBonus);
    });

    it('caps move cost reduction at 90%', () => {
      const inv = createEmptyInventory();
      const gapBoots = ITEM_CATALOG.get('void-gap-walker-boots');
      const torus = ITEM_CATALOG.get('sophia-clifford-torus');
      expect(gapBoots).toBeDefined();
      expect(torus).toBeDefined();

      const equipped = {
        ...inv.equipment,
        boots: gapBoots!,
        offhand: torus!,
      };

      const mod = calculateEquipmentModifier(equipped);
      expect(mod.moveCostReduction).toBeLessThanOrEqual(0.9);
    });
  });

  // ── Nexus Trade Value ───────────────────────────────────────────

  describe('calculateNexusValue', () => {
    it('higher improbability = higher value', () => {
      const item = ITEM_CATALOG.get('proton-triad-helm')!;
      const value1 = calculateNexusValue(item, 10, 3);
      const value2 = calculateNexusValue(item, 100, 3);
      expect(value2).toBeGreaterThan(value1);
    });

    it('higher β₁ at drop = higher value', () => {
      const item = ITEM_CATALOG.get('proton-triad-helm')!;
      const value3 = calculateNexusValue(item, 10, 3);
      const value21 = calculateNexusValue(item, 10, 21);
      expect(value21).toBeGreaterThan(value3);
    });

    it('stronger modifiers = higher value', () => {
      const weak = ITEM_CATALOG.get('barbelo-sliver-blade')!;
      const strong = ITEM_CATALOG.get('void-demiurge-hammer')!;
      const valueWeak = calculateNexusValue(weak, 10, 1);
      const valueStrong = calculateNexusValue(strong, 10, 21);
      expect(valueStrong).toBeGreaterThan(valueWeak);
    });
  });
});
